import strawberry
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, Float
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import relationship, sessionmaker

Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    reviews = relationship('Review', back_populates='product')
    seller_id = Column(Integer, ForeignKey('sellers.id'))
    seller = relationship('Seller', back_populates='products')
    category_id = Column(Integer, ForeignKey('categories.id'))
    category = relationship('Category', back_populates='products')
    images = relationship('Image', back_populates='product')

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(String)
    rating = Column(Float)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('Product', back_populates='reviews')

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', back_populates='seller')

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', back_populates='category')

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('Product', back_populates='images')

engine = create_engine('sqlite:///example.db')
Base.metadata.create_all(engine)
Session = sessionmaker(bind=engine)

@strawberry.type
class ProductType:
    id: int
    name: str
    price: float
    reviews: list['ReviewType']
    seller: 'SellerType'
    category: 'CategoryType'
    images: list['ImageType']

@strawberry.type
class ReviewType:
    id: int
    content: str
    rating: float
    product: ProductType

@strawberry.type
class SellerType:
    id: int
    name: str
    products: list[ProductType]

@strawberry.type
class CategoryType:
    id: int
    name: str
    products: list[ProductType]

@strawberry.type
class ImageType:
    id: int
    url: str
    product: ProductType

@strawberry.type
class Query:
    @strawberry.field
    def product(self, id: int) -> ProductType:
        session = Session()
        product = session.query(Product).filter_by(id=id).first()
        if not product:
            raise strawberry.exceptions.GraphQLException("Product not found")
        return ProductType(
            id=product.id,
            name=product.name,
            price=product.price,
            reviews=[ReviewType(id=r.id, content=r.content, rating=r.rating, product=None) for r in product.reviews],
            seller=SellerType(id=product.seller_id, name=product.seller.name, products=[]),
            category=CategoryType(id=product.category_id, name=product.category.name, products=[]),
            images=[ImageType(id=i.id, url=i.url, product=None) for i in product.images]
        )

schema = strawberry.Schema(query=Query)